={{ (() => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const raw = String($json.cedula ?? $items('BUSCA Y BLOQUEA REGISTRO', 0, 0)[0].json.cedula ?? '').trim();
  if (!raw) return `SELECT 'skip_fallback_sin_cedula' AS status`;

  const cedula = raw.replace(/'/g, "''");

  const hasSnapshot = [
    $json.snapshot_estado_flujo,
    $json.snapshot_fecha_reagenda,
    $json.snapshot_intentos_llamada,
    $json.snapshot_win_tries,
    $json.snapshot_telefono_index,
    $json.snapshot_win_stamp,
    $json.snapshot_fecha_ultima_llamada
  ].some(v => v !== undefined);

  if (hasSnapshot) {
    const snapEstado = String($json.snapshot_estado_flujo ?? cfg.states.pending ?? 'PENDIENTE').replace(/'/g, "''");

    const snapFechaReagendaRaw = $json.snapshot_fecha_reagenda;
    const snapFechaReagendaSql = (snapFechaReagendaRaw == null || String(snapFechaReagendaRaw).trim() === '')
      ? 'NULL'
      : ` '${String(snapFechaReagendaRaw).replace(/'/g, "''")}'::timestamptz `;

    const snapFechaUltRaw = $json.snapshot_fecha_ultima_llamada;
    const snapFechaUltSql = (snapFechaUltRaw == null || String(snapFechaUltRaw).trim() === '')
      ? 'NULL'
      : ` '${String(snapFechaUltRaw).replace(/'/g, "''")}'::timestamptz `;

    const snapIntentosNum = Number($json.snapshot_intentos_llamada);
    const snapIntentosSql = isNaN(snapIntentosNum) ? 'NULL' : String(snapIntentosNum);

    const snapWinTriesNum = Number($json.snapshot_win_tries);
    const snapWinTriesSql = isNaN(snapWinTriesNum) ? 'NULL' : String(snapWinTriesNum);

    const snapTelIndexNum = Number($json.snapshot_telefono_index);
    const snapTelIndexSql = isNaN(snapTelIndexNum) ? 'NULL' : String(snapTelIndexNum);

    const snapWinStampRaw = $json.snapshot_win_stamp;
    const snapWinStampSql = (snapWinStampRaw == null || String(snapWinStampRaw).trim() === '')
      ? 'NULL'
      : ` '${String(snapWinStampRaw).replace(/'/g, "''")}' `;

    return `
      UPDATE ${cfg.db.schema}.${cfg.db.table}
      SET estado_flujo = '${snapEstado}',
          fecha_reagenda = ${snapFechaReagendaSql},
          intentos_llamada = ${snapIntentosSql},
          win_tries = ${snapWinTriesSql},
          telefono_index = ${snapTelIndexSql},
          win_stamp = ${snapWinStampSql},
          fecha_ultima_llamada = ${snapFechaUltSql},
          updated_at = now()
      WHERE id_negocio = '${cedula}'
      RETURNING *;
    `;
  }

  return `
    UPDATE ${cfg.db.schema}.${cfg.db.table}
    SET estado_flujo = '${cfg.states.pending}',
        fecha_reagenda = NULL,
        intentos_llamada = 0,
        win_tries = 0,
        telefono_index = 0,
        win_stamp = NULL,
        fecha_ultima_llamada = NULL,
        updated_at = now()
    WHERE id_negocio = '${cedula}'
    RETURNING *;
  `;
})() }}

